            new() { Id = 16, CourseCode = "HIST 310", Title = "The American Civil War", Description = "An in-depth study of the causes, major battles, political dimensions, and lasting legacy of the American Civil War.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", InstructorName = "Dr. Thomas Reed", InstructorBio = "Dr. Reed is a specialist in modern European political history with a focus on democratic movements and institutional change.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false }
        };

        // Link courses to departments
        foreach (var dept in _departments)
        {
            dept.Courses = _courses.Where(c => c.DepartmentId == dept.Id).ToList();
        }
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Task<bool> SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app this would persist to a database
        return Task.FromResult(!string.IsNullOrWhiteSpace(request.StudentName) &&
                               !string.IsNullOrWhiteSpace(request.StudentId) &&
                               request.CourseId > 0);
    }
}

