}

@page "/courses"
@rendermode InteractiveServer
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Courses</PageTitle>

<div class="container">
    <h1 class="mb-4">Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search courses..." @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    <div class="row">
        @foreach (var course in filteredCourses)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body d-flex flex-column">
                        <h5 class="card-title">@course.Title</h5>
                        <p class="text-muted small">@course.CourseCode &middot; @course.DepartmentName</p>
                        <p class="card-text">@Truncate(course.Description, 100)</p>
                        <div class="mt-auto d-flex justify-content-between align-items-center">
                            <span class="badge bg-primary">@course.Credits Credits</span>
                            <a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>

    @if (!filteredCourses.Any())
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
</div>

@code {
    private List<Department> departments = new();
    private string searchTerm = "";
    private int selectedDepartmentId;

    private List<Course> filteredCourses =>
        CatalogService.GetCourses(searchTerm, selectedDepartmentId > 0 ? selectedDepartmentId : null);

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();

        var uri = new Uri(Navigation.Uri);
        var query = Microsoft.AspNetCore.WebUtilities.QueryHelpers.ParseQuery(uri.Query);
        if (query.TryGetValue("departmentId", out var deptIdStr) && int.TryParse(deptIdStr, out var deptId))
        {
            selectedDepartmentId = deptId;
        }
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Detail")</PageTitle>

<div class="container">
    @if (course is null)
    {
        <div class="alert alert-warning">Course not found.</div>
    }
    else
    {
        <nav aria-label="breadcrumb" class="mb-3">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
                <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
            </ol>
        </nav>

        <h1>@course.Title</h1>
        <p class="text-muted">@course.CourseCode &middot; @course.DepartmentName</p>

        <div class="row mb-4">
            <div class="col-md-8">
                <h5>Description</h5>
                <p>@course.Description</p>

                <h5>Schedule</h5>
                <p>@course.Schedule</p>
            </div>
            <div class="col-md-4">
                <div class="card">
                    <div class="card-body">
                        <h6 class="card-subtitle mb-2 text-muted">Credits</h6>
                        <p class="display-6 fw-bold text-primary">@course.Credits</p>
                        <a href="/enroll?courseId=@course.Id" class="btn btn-primary w-100">Enroll Now</a>
                    </div>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h5>Instructor</h5>
                <h6>@course.InstructorName</h6>
                <p class="text-muted">@course.InstructorBio</p>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private UniversityCourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

